    fputc(0x15, f); fputc(0x01, f); fputc(0x03, f); fputc(0x00, f);
    fputc(0x01, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);
    fputc(0x04, f); fputc(0x00, f); fputc(0x00, f); fputc(0x00, f);

