    fputc(0x10, f); fputc(0x00, f);
    fputc(0x10, f); fputc(0x00, f);
    fputc(0x10, f); fputc(0x00, f);

    /* Pixel data at offset 142: 1 pixel, R=65535, G=65535, B=65535, A=65535 */
    /* opacity = MaxRGB = 65535, so condition q->opacity != MaxRGB is FALSE */
    /* The block is skipped, but the uninitialized value is read from pixel cache */
    /* Because the pixel cache may have uninitialized memory at this location */
    fputc(0xFF, f); fputc(0xFF, f); /* R = 65535 */
    fputc(0xFF, f); fputc(0xFF, f); /* G = 65535 */
    fputc(0xFF, f); fputc(0xFF, f); /* B = 65535 */
    fputc(0xFF, f); fputc(0xFF, f); /* A = 65535 */

    fclose(f);
    return 0;
